    ('zephid''s embrace', 'Zephid''s Embrace', '606127a661ca7d09cfb1e3e9eea926f8', 'battle_rule_v1:cfa9b423ec665e122a4e16b84a0c355d', '{"ability_kind":"aura_static","attached_keywords":["flying","shroud"],"aura":true,"battle_model_scope":"xmage_aura_static_power_toughness_attachment_v1","effect":"aura_static_attachment","enchant_target":"creature","enchant_target_controller":"any","grants_flying":true,"grants_shroud":true,"instant":false,"power_boost":2,"sorcery":false,"static_power_bonus":2,"static_toughness_bonus":2,"target":"creature","target_constraints":{"card_types":["creature"],"zone":"battlefield"},"toughness_boost":2,"xmage_ability_classes":["EnchantAbility","FlyingAbility","ShroudAbility","SimpleStaticAbility"],"xmage_effect_classes":["AttachEffect","BoostEnchantedEffect","GainAbilityAttachedEffect"]}'::jsonb, '{"category":"support","effect":"aura_static_attachment","subtype":"aura_static_pump","target":"creature"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'XMage authoritative exact-scope split: local class ZephidsEmbrace translated into ManaLoom runtime scope xmage_aura_static_power_toughness_attachment_v1. This row is package-ready only because the source signature is a narrow Aura attachment with static enchanted-creature power/toughness modifier with focused runtime coverage.', 'deprecate_nonmatching_rows')
),
  counts AS (
    SELECT
      p.card_name,
      p.normalized_name,
      p.oracle_hash,
      count(c.id) AS target_card_rows,
      min(c.id::text)::uuid AS canonical_card_id
    FROM proposed p
    LEFT JOIN public.cards c
      ON (
           lower(c.name) = p.normalized_name
           OR split_part(lower(c.name), ' // ', 1) = p.normalized_name
         )
     AND md5(coalesce(c.oracle_text, '')) = p.oracle_hash
    GROUP BY p.card_name, p.normalized_name, p.oracle_hash
  )
  SELECT jsonb_agg(counts ORDER BY card_name)
    INTO v_missing
  FROM counts
  WHERE target_card_rows < 1;

  IF v_missing IS NOT NULL THEN
    RAISE EXCEPTION 'XMage batch package abort: expected at least one Oracle-hash-matched card row for every proposed card: %', v_missing;
  END IF;
END $$;

